# Tags visible on EC2 instance:
$ aws ec2 describe-tags --filters "Name=resource-id,Values=i-0abc123"
{
  "Tags": [
    {"Key": "team", "Value": "platform"},
    {"Key": "project", "Value": "api-gateway"},
    {"Key": "environment", "Value": "production"}
  ]
}

# But in Cost Explorer → Group by → Tag:
# Only 'aws:createdBy' appears
# No custom tags visible

# terraform provider config:
provider "aws" {
  region = "us-east-1"
  default_tags {
    tags = {
      environment = "production"
      team        = "platform"
      managed_by  = "terraform"
    }
  }
}

# terraform plan output:
  # aws_instance.api_server will be updated in-place
  ~ resource "aws_instance" "api_server" {
      ~ tags = {
          + "environment" = "production"
          + "team"        = "platform"
          - "owner"       = "john" -> null
        }
    }

# Current state - tags defined separately:

# modules/aws/main.tf
resource "aws_instance" "web" {
  tags = {
    team        = var.team
    environment = var.environment
    cost-center = var.cost_center
  }
}

# modules/gcp/main.tf
resource "google_compute_instance" "web" {
  labels = {
    team        = lower(var.team)
    environment = lower(var.environment)
    cost_center = lower(var.cost_center)
  }
}

# modules/azure/main.tf
resource "azurerm_virtual_machine" "web" {
  tags = {
    Team        = var.team
    Environment = var.environment
    CostCenter  = var.cost_center
  }
}
